/** @type {import('tailwindcss').Config} */
export default {
  content: [
    "./index.html",
    "./src/**/*.{js,ts,jsx,tsx}",
  ],
  theme: {
    extend: {
      colors: {
        alipay: {
          blue: '#1677FF',
          'blue-dark': '#0958D9',
          'blue-light': '#E6F4FF',
          'blue-gradient-start': '#1677FF',
          'blue-gradient-end': '#0958D9',
          bg: '#F5F5F5',
          card: '#FFFFFF',
          text: '#333333',
          'text-secondary': '#666666',
          'text-tertiary': '#999999',
          green: '#19C019',
          orange: '#FF6B35',
          divider: '#EEEEEE',
        },
      },
      fontFamily: {
        sans: ['-apple-system', 'BlinkMacSystemFont', '"PingFang SC"', '"Microsoft YaHei"', '"Helvetica Neue"', 'sans-serif'],
      },
      borderRadius: {
        card: '12px',
        btn: '8px',
        pill: '24px',
      },
      fontSize: {
        'balance': ['28px', '36px'],
        'balance-sm': ['20px', '28px'],
      },
      spacing: {
        '18': '72px',
      },
    },
  },
  plugins: [],
}

import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'
import { VitePWA } from 'vite-plugin-pwa'

export default defineConfig({
  plugins: [
    react(),
    VitePWA({
      registerType: 'autoUpdate',
      includeAssets: ['favicon.svg'],
      manifest: {
        name: '支付宝',
        short_name: '支付宝',
        description: '支付宝 - 生活好帮手',
        theme_color: '#1677FF',
        background_color: '#F5F5F5',
        display: 'standalone',
        icons: [
          {
            src: 'favicon.svg',
            sizes: '192x192',
            type: 'image/svg+xml',
          },
        ],
      },
      workbox: {
        runtimeCaching: [
          {
            urlPattern: /\.(?:js|css|html|png|jpg|jpeg|svg)$/,
            handler: 'CacheFirst',
            options: {
              cacheName: 'alipay-assets',
              expiration: {
                maxEntries: 100,
                maxAgeSeconds: 60 * 60 * 24 * 30,
              },
            },
          },
        ],
      },
    }),
  ],
})

