import { useState } from 'react'

function BalanceCard() {
  const [balance, setBalance] = useState(() => {
    return localStorage.getItem('alipay_balance') || '12,345.67'
  })
  const [visible, setVisible] = useState(true)
  const [devMode, setDevMode] = useState(false)
  const [editValue, setEditValue] = useState(balance)
  let clickTimer = null

  const handleBalanceClick = () => {
    if (!clickTimer) {
      clickTimer = setTimeout(() => {
        setDevMode(true)
        setEditValue(balance)
        clickTimer = null
      }, 1500)
    }
  }

  const handleBalanceClickCancel = () => {
    if (clickTimer) {
      clearTimeout(clickTimer)
      clickTimer = null
    }
  }

  const handleSave = () => {
    const val = editValue.replace(/[^\d.]/g, '')
    if (val && !isNaN(val)) {
      const formatted = Number(val).toLocaleString('zh-CN', {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
      })
      setBalance(formatted)
      localStorage.setItem('alipay_balance', formatted)
    }
    setDevMode(false)
  }

  return (
    <div className="bg-gradient-to-b from-alipay-blue to-alipay-blue-dark px-4 pb-6 pt-2">
      {/* Balance area */}
      <div className="mt-2">
        <div className="flex items-center gap-2 text-white/80 text-sm">
          <span>余额</span>
          <button
            onClick={() => setVisible(!visible)}
            className="active:opacity-60"
          >
            {visible ? (
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none">
                <circle cx="12" cy="12" r="3" stroke="white" strokeWidth="1.5"/>
                <path d="M2 12s4-8 10-8 10 8 10 8-4 8-10 8-10-8-10-8z" stroke="white" strokeWidth="1.5"/>
              </svg>
            ) : (
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none">
                <path d="M2 2l20 20M6.5 6.5A9.5 9.5 0 0112 4c6 0 10 8 10 8a12.6 12.6 0 01-3.5 4.8M9.5 4.5A9.8 9.8 0 0112 4M4.5 9.5A12.3 12.3 0 002 12s4 8 10 8a9.8 9.8 0 005-1.5" stroke="white" strokeWidth="1.5" strokeLinecap="round"/>
              </svg>
            )}
          </button>
        </div>

        <div
          className="mt-1 select-none"
          onMouseDown={handleBalanceClick}
          onMouseUp={handleBalanceClickCancel}
          onMouseLeave={handleBalanceClickCancel}
          onTouchStart={handleBalanceClick}
          onTouchEnd={handleBalanceClickCancel}
        >
          {devMode ? (
            <div className="flex items-center gap-2 mt-2" onClick={e => e.stopPropagation()}>
              <span className="text-white text-lg">¥</span>
              <input
                autoFocus
                type="text"
                value={editValue}
                onChange={e => setEditValue(e.target.value)}
                className="bg-white/20 text-white text-2xl font-bold px-3 py-1 rounded-btn outline-none w-40 border border-white/30"
              />
              <button
                onClick={handleSave}
                className="bg-white text-alipay-blue px-3 py-1 rounded-btn text-sm font-medium active:opacity-80"
              >
                确定
              </button>
            </div>
          ) : (
            <div className="flex items-baseline gap-1">
              <span className="text-white text-sm">¥</span>
              <span className="text-white text-balance font-bold tracking-tight">
                {visible ? balance : '******'}
              </span>
            </div>
          )}
        </div>

        {devMode && (
          <p className="text-white/50 text-xs mt-1">开发者模式 - 输入新金额后点击确定</p>
        )}
      </div>

      {/* Quick action buttons */}
      <div className="flex justify-between mt-5">
        {[
          { label: '转账', icon: 'transfer' },
          { label: '充值', icon: 'topup' },
          { label: '还款', icon: 'repay' },
          { label: '缴费', icon: 'bill' },
        ].map((action, i) => (
          <button
            key={i}
            className="flex flex-col items-center gap-1 active:opacity-60 transition-opacity"
          >
            <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center">
              <QuickIcon type={action.icon} />
            </div>
            <span className="text-white text-xs">{action.label}</span>
          </button>
        ))}
      </div>
    </div>
  )
}

function QuickIcon({ type }) {
  const icons = {
    transfer: (
      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
        <path d="M17 4l4 4-4 4M21 8H3M7 20l-4-4 4-4M3 16h18"/>
      </svg>
    ),
    topup: (
      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="1.5" strokeLinecap="round">
        <path d="M12 2v20M17 7H9.5A3.5 3.5 0 006 10.5v0A3.5 3.5 0 009.5 14H14a3 3 0 010 6h-7"/>
      </svg>
    ),
    repay: (
      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="1.5">
        <rect x="2" y="4" width="20" height="16" rx="3"/>
        <path d="M2 10h20M6 16h4" strokeLinecap="round"/>
      </svg>
    ),
    bill: (
      <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
        <path d="M4 6h16v16H4zM8 2v4M16 2v4M8 12h8M8 16h6"/>
      </svg>
    ),
  }
  return icons[type] || null
}

export default BalanceCard

import { useState } from 'react'

const tabs = [
  {
    name: '首页',
    icon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <path d="M3 12L12 3l9 9" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
        <path d="M5 10v10h14V10" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round"/>
      </svg>
    ),
    activeIcon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <path d="M3 12L12 3l9 9" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
        <path d="M5 10v10h14V10" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round" fill="currentColor" fillOpacity="0.15"/>
      </svg>
    ),
  },
  {
    name: '理财',
    icon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <rect x="2" y="4" width="20" height="16" rx="2" stroke="currentColor" strokeWidth="1.5"/>
        <path d="M7 14l3-3 3 3 4-5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
      </svg>
    ),
    activeIcon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <rect x="2" y="4" width="20" height="16" rx="2" stroke="currentColor" strokeWidth="1.5"/>
        <path d="M7 14l3-3 3 3 4-5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
      </svg>
    ),
  },
  {
    name: '消息',
    icon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <path d="M21 15a1 1 0 01-1 1H7l-4 4V5a1 1 0 011-1h16a1 1 0 011 1v10z" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round"/>
      </svg>
    ),
    activeIcon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <path d="M21 15a1 1 0 01-1 1H7l-4 4V5a1 1 0 011-1h16a1 1 0 011 1v10z" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round"/>
      </svg>
    ),
  },
  {
    name: '我的',
    icon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <circle cx="12" cy="8" r="4" stroke="currentColor" strokeWidth="1.5"/>
        <path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
      </svg>
    ),
    activeIcon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <circle cx="12" cy="8" r="4" stroke="currentColor" strokeWidth="1.5"/>
        <path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
      </svg>
    ),
  },
]

export default function BottomNav() {
  const [active, setActive] = useState(0)

  return (
    <div className="fixed bottom-0 left-0 right-0 max-w-[430px] mx-auto bg-white border-t border-alipay-divider safe-area-bottom">
      <div className="flex justify-around items-center h-14">
        {tabs.map((tab, i) => (
          <button
            key={i}
            onClick={() => setActive(i)}
            className={`flex flex-col items-center gap-0.5 active:opacity-60 transition-colors ${
              active === i ? 'text-alipay-blue' : 'text-alipay-text-tertiary'
            }`}
          >
            {active === i ? tab.activeIcon : tab.icon}
            <span className="text-[10px]">{tab.name}</span>
          </button>
        ))}
      </div>
    </div>
  )
}

export default function NoticeCard() {
  const notices = [
    { title: '余额宝', desc: '七日年化 1.8750%', color: '#FF6B35', icon: '💰' },
    { title: '花呗', desc: '本月账单待还 ¥0.00', color: '#1677FF', icon: '💳' },
  ]

  return (
    <div className="mx-4 mt-3 space-y-3">
      {notices.map((n, i) => (
        <div
          key={i}
          className="bg-alipay-card rounded-card px-4 py-3 flex items-center justify-between active:opacity-60 cursor-pointer"
        >
          <div className="flex items-center gap-3">
            <div
              className="w-10 h-10 rounded-full flex items-center justify-center text-lg"
              style={{ backgroundColor: `${n.color}15` }}
            >
              {n.icon}
            </div>
            <div>
              <div className="text-sm font-medium text-alipay-text">{n.title}</div>
              <div className="text-xs text-alipay-text-secondary mt-0.5">{n.desc}</div>
            </div>
          </div>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#CCCCCC" strokeWidth="2" strokeLinecap="round">
            <path d="M9 18l6-6-6-6"/>
          </svg>
        </div>
      ))}
    </div>
  )
}

import Header from './components/Header'
import BalanceCard from './components/BalanceCard'
import ServiceGrid from './components/ServiceGrid'
import NoticeCard from './components/NoticeCard'
import BottomNav from './components/BottomNav'

function App() {
  return (
    <div className="min-h-screen bg-alipay-bg pb-16">
      {/* Blue header section */}
      <div className="bg-gradient-to-b from-alipay-blue to-alipay-blue-dark">
        <Header />
        <BalanceCard />
      </div>

      {/* Service grid */}
      <ServiceGrid />

      {/* Notice cards */}
      <NoticeCard />

      {/* Bottom padding spacer for content */}
      <div className="h-4" />
      <p className="text-center text-alipay-text-tertiary text-xs pb-4">
        长按余额区域进入开发者模式
      </p>

      {/* Bottom navigation */}
      <BottomNav />
    </div>
  )
}

export default App

