import { useState } from 'react'
import HomePage from './pages/HomePage'
import WealthPage from './pages/WealthPage'
import MessagesPage from './pages/MessagesPage'
import ProfilePage from './pages/ProfilePage'
import BalancePage from './pages/BalancePage'

const tabs = [
  {
    key: 'home',
    name: '首页',
    icon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <path d="M3 12L12 3l9 9" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
        <path d="M5 10v10h14V10" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round"/>
      </svg>
    ),
  },
  {
    key: 'wealth',
    name: '理财',
    icon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <rect x="2" y="4" width="20" height="16" rx="2" stroke="currentColor" strokeWidth="1.5"/>
        <path d="M7 14l3-3 3 3 4-5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
      </svg>
    ),
  },
  {
    key: 'messages',
    name: '消息',
    icon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <path d="M21 15a1 1 0 01-1 1H7l-4 4V5a1 1 0 011-1h16a1 1 0 011 1v10z" stroke="currentColor" strokeWidth="1.5" strokeLinejoin="round"/>
      </svg>
    ),
  },
  {
    key: 'profile',
    name: '我的',
    icon: (
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <circle cx="12" cy="8" r="4" stroke="currentColor" strokeWidth="1.5"/>
        <path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
      </svg>
    ),
  },
]

function BottomNav({ active, onChange }) {
  return (
    <div className="fixed bottom-0 left-0 right-0 max-w-[430px] mx-auto bg-white border-t border-alipay-divider z-50">
      <div className="flex justify-around items-center h-14 pb-safe">
        {tabs.map((tab) => (
          <button
            key={tab.key}
            onClick={() => onChange(tab.key)}
            className={`flex flex-col items-center gap-0.5 active:opacity-60 transition-colors w-full py-1 ${
              active === tab.key ? 'text-alipay-blue' : 'text-alipay-text-tertiary'
            }`}
          >
            {tab.icon}
            <span className="text-[10px]">{tab.name}</span>
          </button>
        ))}
      </div>
    </div>
  )
}

function App() {
  const [activeTab, setActiveTab] = useState('home')
  const [subPage, setSubPage] = useState(null)

  const handleNavigate = (page) => {
    setSubPage(page)
  }

  const handleBack = () => {
    setSubPage(null)
  }

  // Balance secondary page
  if (subPage === 'balance') {
    return (
      <div className="max-w-[430px] mx-auto min-h-screen bg-alipay-bg relative overflow-hidden">
        <BalancePage onBack={handleBack} />
      </div>
    )
  }

  const renderPage = () => {
    switch (activeTab) {
      case 'home':
        return <HomePage onNavigate={handleNavigate} />
      case 'wealth':
        return <WealthPage />
      case 'messages':
        return <MessagesPage />
      case 'profile':
        return <ProfilePage onNavigate={handleNavigate} />
      default:
        return <HomePage onNavigate={handleNavigate} />
    }
  }

  return (
    <div className="max-w-[430px] mx-auto min-h-screen bg-alipay-bg relative overflow-hidden">
      {renderPage()}
      <BottomNav active={activeTab} onChange={setActiveTab} />
    </div>
  )
}

export default App

