  { title: '转账-转到银行卡', time: '2024-05-17 14:00', amount: '-1,500.00', type: 'out' },
  { title: '收款-李四', time: '2024-05-16 09:20', amount: '+800.00', type: 'in' },
]

export default function BalancePage({ onBack }) {
  const [balance, setBalance] = useState(() => localStorage.getItem('alipay_balance') || '12,345.67')
  const [visible, setVisible] = useState(true)
  const [devMode, setDevMode] = useState(false)
  const [editValue, setEditValue] = useState(balance)
  const [activeTab, setActiveTab] = useState('all')
  let timer = null

  const startPress = () => { timer = setTimeout(() => { setDevMode(true); setEditValue(balance); timer = null }, 2000) }
  const cancelPress = () => { if (timer) { clearTimeout(timer); timer = null } }

  const save = () => {
    const v = editValue.replace(/[^\d.]/g, '')
    if (v && !isNaN(v)) {
      const f = Number(v).toLocaleString('zh-CN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })
      setBalance(f)
      localStorage.setItem('alipay_balance', f)
    }
    setDevMode(false)
  }

  return (
    <div className="min-h-screen bg-[#F5F5F5] pb-20">
      {/* Header */}
      <div className="bg-alipay-blue px-4 pt-2 pb-8">
        <div className="flex items-center justify-between">
          <button onClick={onBack} className="active:opacity-60 p-1 -ml-1">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M15 18l-6-6 6-6"/>
            </svg>
          </button>
          <span className="text-white text-lg font-medium">余额</span>
          <button className="active:opacity-60">
            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="1.5">
              <circle cx="12" cy="5" r="1.3" fill="white" stroke="none"/>
              <circle cx="12" cy="12" r="1.3" fill="white" stroke="none"/>
              <circle cx="12" cy="19" r="1.3" fill="white" stroke="none"/>
            </svg>
          </button>
        </div>

        {/* Balance display */}
        <div className="mt-8 text-center">
          <div className="flex items-center justify-center gap-1.5 text-white/70 text-sm">
            <span>余额 (元)</span>
            <button onClick={() => setVisible(!visible)} className="active:opacity-60">
              {visible ? (
                <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="rgba(255,255,255,0.7)" strokeWidth="1.5">
                  <circle cx="12" cy="12" r="3"/><path d="M2 12s4-8 10-8 10 8 10 8-4 8-10 8-10-8-10-8z"/>
                </svg>
              ) : (
                <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="rgba(255,255,255,0.7)" strokeWidth="1.5" strokeLinecap="round">
                  <path d="M2 2l20 20"/><path d="M6.5 6.5A9.5 9.5 0 0112 4c6 0 10 8 10 8a12.6 12.6 0 01-3.5 4.8"/>
                </svg>
              )}
            </button>
          </div>

          <div className="mt-2 select-none" onMouseDown={startPress} onMouseUp={cancelPress} onMouseLeave={cancelPress} onTouchStart={startPress} onTouchEnd={cancelPress}>
            {devMode ? (
              <div className="flex items-center justify-center gap-2" onClick={e => e.stopPropagation()}>
                <span className="text-white text-lg">¥</span>
                <input autoFocus value={editValue} onChange={e => setEditValue(e.target.value)}
                  className="bg-white/20 text-white text-2xl font-bold px-3 py-1 rounded-lg outline-none w-40 border border-white/30 text-center" />
                <button onClick={save} className="bg-white text-[#3775F6] px-3 py-1 rounded-lg text-sm font-medium active:opacity-80">确定</button>
              </div>
            ) : (
              <div className="text-white text-[40px] font-bold tracking-tight">
                {visible ? balance : '******'}
              </div>
            )}
          </div>
          {devMode && <p className="text-white/45 text-xs mt-2">开发者模式 · 长按余额触发</p>}

          {/* Action buttons */}
          <div className="flex justify-center gap-10 mt-6">
            {[{ label: '充值', icon: '📥' }, { label: '提现', icon: '📤' }, { label: '转账', icon: '💸' }].map((a, i) => (
              <button key={i} className="flex flex-col items-center gap-1.5 active:opacity-60">
                <div className="w-12 h-12 rounded-full bg-white/20 flex items-center justify-center text-xl">{a.icon}</div>
                <span className="text-white text-xs">{a.label}</span>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Transaction tabs + list */}
      <div className="bg-white mx-4 -mt-3 relative z-10 rounded-card shadow-sm">
        <div className="flex border-b border-[#EEE]">
          {[
            { key: 'all', label: '全部' },
            { key: 'income', label: '收入' },
            { key: 'outcome', label: '支出' },
          ].map((tab) => (
            <button key={tab.key} onClick={() => setActiveTab(tab.key)}
              className={`flex-1 py-3 text-sm transition-colors relative ${activeTab === tab.key ? 'text-[#3775F6] font-medium' : 'text-[#666]'}`}>
              {tab.label}
              {activeTab === tab.key && <div className="absolute bottom-0 left-1/2 -translate-x-1/2 w-6 h-0.5 bg-[#3775F6] rounded-full" />}
            </button>
          ))}
        </div>

        <div>
          {transactions.filter((t) => {
            if (activeTab === 'income') return t.type === 'in'
            if (activeTab === 'outcome') return t.type === 'out'
            return true
          }).map((tx, i) => (
            <div key={i} className="px-4 py-3 flex items-center justify-between border-b border-[#EEE] last:border-b-0 active:bg-gray-50 cursor-pointer">
              <div>
                <div className="text-sm text-[#333]">{tx.title}</div>
                <div className="text-xs text-[#999] mt-0.5">{tx.time}</div>
              </div>
              <span className={`text-sm font-medium ${tx.type === 'in' ? 'text-[#19C019]' : 'text-[#333]'}`}>{tx.amount}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}

