]

export default function BalancePage({ onBack }) {
  const [balance, setBalance] = useState(() => {
    return localStorage.getItem('alipay_balance') || '12,345.67'
  })
  const [visible, setVisible] = useState(true)
  const [devMode, setDevMode] = useState(false)
  const [editValue, setEditValue] = useState(balance)
  const [activeTab, setActiveTab] = useState('all')
  let clickTimer = null

  const handleLongPress = () => {
    if (!clickTimer) {
      clickTimer = setTimeout(() => {
        setDevMode(true)
        setEditValue(balance)
        clickTimer = null
      }, 2000)
    }
  }

  const cancelLongPress = () => {
    if (clickTimer) {
      clearTimeout(clickTimer)
      clickTimer = null
    }
  }

  const handleSave = () => {
    const val = editValue.replace(/[^\d.]/g, '')
    if (val && !isNaN(val)) {
      const formatted = Number(val).toLocaleString('zh-CN', {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
      })
      setBalance(formatted)
      localStorage.setItem('alipay_balance', formatted)
    }
    setDevMode(false)
  }

  return (
    <div className="min-h-screen bg-alipay-bg pb-20">
      {/* Header */}
      <div className="bg-gradient-to-b from-alipay-blue to-alipay-blue-dark px-4 pt-3 pb-8">
