              <path d="M15 18l-6-6 6-6"/>
            </svg>
          </button>
          <span className="text-white text-lg font-medium">余额</span>
          <button className="active:opacity-60">
            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="1.5" strokeLinecap="round">
              <circle cx="12" cy="5" r="1" fill="white" stroke="none"/>
              <circle cx="12" cy="12" r="1" fill="white" stroke="none"/>
              <circle cx="12" cy="19" r="1" fill="white" stroke="none"/>
            </svg>
          </button>
        </div>

        {/* Balance display */}
        <div className="mt-6 text-center">
          <div className="flex items-center justify-center gap-2 text-white/80 text-sm">
            <span>余额 (元)</span>
            <button onClick={() => setVisible(!visible)} className="active:opacity-60">
              {visible ? (
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
                  <circle cx="12" cy="12" r="3" stroke="white" strokeWidth="1.5"/>
                  <path d="M2 12s4-8 10-8 10 8 10 8-4 8-10 8-10-8-10-8z" stroke="white" strokeWidth="1.5"/>
                </svg>
              ) : (
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
                  <path d="M2 2l20 20" stroke="white" strokeWidth="1.5" strokeLinecap="round"/>
                  <path d="M6.5 6.5A9.5 9.5 0 0112 4c6 0 10 8 10 8a12.6 12.6 0 01-3.5 4.8" stroke="white" strokeWidth="1.5" strokeLinecap="round"/>
                </svg>
              )}
            </button>
          </div>
          <div
            className="mt-2 select-none"
            onMouseDown={handleLongPress}
            onMouseUp={cancelLongPress}
            onMouseLeave={cancelLongPress}
            onTouchStart={handleLongPress}
            onTouchEnd={cancelLongPress}
          >
            {devMode ? (
              <div className="flex items-center justify-center gap-2" onClick={e => e.stopPropagation()}>
                <span className="text-white text-lg">¥</span>
                <input
                  autoFocus
                  type="text"
                  value={editValue}
                  onChange={e => setEditValue(e.target.value)}
                  className="bg-white/20 text-white text-2xl font-bold px-3 py-1 rounded-btn outline-none w-40 border border-white/30 text-center"
                />
                <button
                  onClick={handleSave}
                  className="bg-white text-alipay-blue px-3 py-1 rounded-btn text-sm font-medium active:opacity-80"
                >
                  确定
                </button>
              </div>
            ) : (
              <div className="text-white text-4xl font-bold tracking-tight">
                {visible ? balance : '******'}
              </div>
            )}
          </div>
          {devMode && (
            <p className="text-white/50 text-xs mt-2">开发者模式 - 长按余额触发，输入新金额后确定</p>
          )}

          {/* Action buttons */}
          <div className="flex justify-center gap-8 mt-6">
