              { label: '充值', icon: '📥' },
              { label: '提现', icon: '📤' },
              { label: '转账', icon: '💸' },
            ].map((a, i) => (
              <button key={i} className="flex flex-col items-center gap-1 active:opacity-60">
                <div className="w-12 h-12 rounded-full bg-white/20 flex items-center justify-center text-xl">
                  {a.icon}
                </div>
                <span className="text-white text-xs">{a.label}</span>
              </button>
            ))}
          </div>
        </div>
      </div>

