            .map((tx, i) => (
              <div
                key={i}
                className="px-4 py-3 flex items-center justify-between border-b border-alipay-divider last:border-b-0 active:bg-gray-50 cursor-pointer"
              >
                <div>
                  <div className="text-sm text-alipay-text">{tx.title}</div>
                  <div className="text-xs text-alipay-text-tertiary mt-0.5">{tx.time}</div>
                </div>
                <span
                  className={`text-sm font-medium ${
                    tx.type === 'in' ? 'text-alipay-green' : 'text-alipay-text'
                  }`}
                >
                  {tx.amount}
                </span>
              </div>
            ))}
        </div>
      </div>
    </div>
  )
}

