    profile: <ProfilePage onNavigate={setSubPage} />,
  }

  return (
    <div className="max-w-[430px] mx-auto min-h-screen bg-[#F5F5F5] relative overflow-hidden">
      {pages[activeTab]}
      <BottomNav active={activeTab} onChange={setActiveTab} />
    </div>
  )
}

export default App

